MAP
  NAME       "nz_kriging_scenarios"
  SIZE       340 440
  EXTENT     990000 4730000 2120000 6190000
  UNITS      meters
  IMAGETYPE  "png"
  IMAGECOLOR 222 234 244
  CONFIG "MS_ERRORFILE" "stderr"
  PROJECTION
    "init=epsg:2193"
  END

  #=== scenario 1: dense, even network =================================#
  LAYER
    NAME "idw_regular"
    TYPE raster
    STATUS off
    CONNECTIONTYPE idw
    CONNECTION "grid_regular"
    MASK "landmask"
    PROCESSING "RANGE_COLORSPACE=RGB"
    PROCESSING "IDW_RADIUS=250"
    PROCESSING "IDW_POWER=2"
    PROCESSING "IDW_COMPUTE_BORDERS=OFF"
    OFFSITE 0 0 0
    CLASS
      STYLE                                    # < 250 mm
        COLORRANGE "#8b0000" "#8b0000"
        DATARANGE  0 8.33
      END
      STYLE                                    # 250 - 500
        COLORRANGE "#e41a1c" "#e41a1c"
        DATARANGE  8.33 16.67
      END
      STYLE                                    # 500 - 750
        COLORRANGE "#ff7f00" "#ff7f00"
        DATARANGE  16.67 25
      END
      STYLE                                    # 750 - 1000
        COLORRANGE "#ffe93a" "#ffe93a"
        DATARANGE  25 33.33
      END
      STYLE                                    # 1000 - 1250
        COLORRANGE "#a6d96a" "#a6d96a"
        DATARANGE  33.33 41.67
      END
      STYLE                                    # 1250 - 1500
        COLORRANGE "#41ab5d" "#41ab5d"
        DATARANGE  41.67 50
      END
      STYLE                                    # 1500 - 2000
        COLORRANGE "#1d9182" "#1d9182"
        DATARANGE  50 66.67
      END
      STYLE                                    # 2000 - 3000
        COLORRANGE "#6baed6" "#6baed6"
        DATARANGE  66.67 100
      END
      STYLE                                    # 3000 - 4000
        COLORRANGE "#2166ac" "#2166ac"
        DATARANGE  100 133.33
      END
      STYLE                                    # > 4000 mm
        COLORRANGE "#6a3d9a" "#6a3d9a"
        DATARANGE  133.33 260
      END
    END
  END
  LAYER
    NAME "km_regular"
    TYPE raster
    STATUS off
    CONNECTIONTYPE kriging
    CONNECTION "grid_regular"
    MASK "landmask"
    PROCESSING "RANGE_COLORSPACE=RGB"
    PROCESSING "KRIGING_MODEL=EXPONENTIAL"
    PROCESSING "KRIGING_TYPE=ORDINARY"
    PROCESSING "KRIGING_NEIGHBORS=16"
    PROCESSING "KRIGING_RANGE=40"
    PROCESSING "KRIGING_SILL=2000"
    PROCESSING "KRIGING_NUGGET=0"
    PROCESSING "BANDS=1"
    OFFSITE 0 0 0
    CLASS
      STYLE                                    # < 250 mm
        COLORRANGE "#8b0000" "#8b0000"
        DATARANGE  0 8.33
      END
      STYLE                                    # 250 - 500
        COLORRANGE "#e41a1c" "#e41a1c"
        DATARANGE  8.33 16.67
      END
      STYLE                                    # 500 - 750
        COLORRANGE "#ff7f00" "#ff7f00"
        DATARANGE  16.67 25
      END
      STYLE                                    # 750 - 1000
        COLORRANGE "#ffe93a" "#ffe93a"
        DATARANGE  25 33.33
      END
      STYLE                                    # 1000 - 1250
        COLORRANGE "#a6d96a" "#a6d96a"
        DATARANGE  33.33 41.67
      END
      STYLE                                    # 1250 - 1500
        COLORRANGE "#41ab5d" "#41ab5d"
        DATARANGE  41.67 50
      END
      STYLE                                    # 1500 - 2000
        COLORRANGE "#1d9182" "#1d9182"
        DATARANGE  50 66.67
      END
      STYLE                                    # 2000 - 3000
        COLORRANGE "#6baed6" "#6baed6"
        DATARANGE  66.67 100
      END
      STYLE                                    # 3000 - 4000
        COLORRANGE "#2166ac" "#2166ac"
        DATARANGE  100 133.33
      END
      STYLE                                    # > 4000 mm
        COLORRANGE "#6a3d9a" "#6a3d9a"
        DATARANGE  133.33 260
      END
    END
  END
  LAYER
    NAME "sd_regular"
    TYPE raster
    STATUS off
    CONNECTIONTYPE kriging
    CONNECTION "grid_regular"
    MASK "landmask"
    PROCESSING "RANGE_COLORSPACE=RGB"
    PROCESSING "KRIGING_MODEL=EXPONENTIAL"
    PROCESSING "KRIGING_TYPE=ORDINARY"
    PROCESSING "KRIGING_NEIGHBORS=16"
    PROCESSING "KRIGING_RANGE=40"
    PROCESSING "KRIGING_SILL=2000"
    PROCESSING "KRIGING_NUGGET=0"
    PROCESSING "BANDS=2"
    OFFSITE 0 0 0
    CLASS
      STYLE
        COLORRANGE "#440154" "#3b528b"
        DATARANGE 0 11.25
      END
      STYLE
        COLORRANGE "#3b528b" "#21908c"
        DATARANGE 11.25 22.5
      END
      STYLE
        COLORRANGE "#21908c" "#5dc863"
        DATARANGE 22.5 33.75
      END
      STYLE
        COLORRANGE "#5dc863" "#fde725"
        DATARANGE 33.75 45
      END
    END
  END

