  #=== sample sources, basemap, labelled cities ========================#
  LAYER
    NAME "grid_regular"
    TYPE point
    STATUS off
    CONNECTIONTYPE OGR
    CONNECTION "grid_nz_regular.csv"
    DATA "grid_nz_regular"
    PROJECTION
      "init=epsg:4326"
    END
    CLASS
      STYLE
        SIZE [weight]
      END
    END
  END
  LAYER
    NAME "grid_clustered"
    TYPE point
    STATUS off
    CONNECTIONTYPE OGR
    CONNECTION "grid_nz_clustered.csv"
    DATA "grid_nz_clustered"
    PROJECTION
      "init=epsg:4326"
    END
    CLASS
      STYLE
        SIZE [weight]
      END
    END
  END
  LAYER
    NAME "landmask"
    TYPE polygon
    STATUS off
    CONNECTIONTYPE OGR
    CONNECTION "nz_coast.geojson"
    DATA "nz_coast"
    PROJECTION
      "init=epsg:4326"
    END
    CLASS
      STYLE
        COLOR 0 0 0
      END
    END
  END
  LAYER
    NAME "coastline"
    TYPE line
    STATUS on
    CONNECTIONTYPE OGR
    CONNECTION "nz_coast.geojson"
    DATA "nz_coast"
    PROJECTION
      "init=epsg:4326"
    END
    CLASS
      STYLE
        COLOR 90 110 130
        WIDTH 0.6
      END
    END
  END
  LAYER
    NAME "cities"
    TYPE point
    STATUS on
    CONNECTIONTYPE OGR
    CONNECTION "cities_major.csv"
    DATA "cities_major"
    PROJECTION
      "init=epsg:4326"
    END
    CLASS
      STYLE
        SYMBOL "circle"
        SIZE 5
        COLOR 20 20 20
        OUTLINECOLOR 255 255 255
        WIDTH 1
      END
    END
  END

  SYMBOL
    NAME  "circle"
    TYPE  ellipse
    FILLED true
    POINTS 1 1 END
  END
END
